static inline Py_ssize_t _Py_atomic_size_get(Py_ssize_t *var)
{
#if SIZEOF_VOID_P == 8
    Py_BUILD_ASSERT(sizeof(__int64) == sizeof(*var));
    volatile __int64 *volatile_var = (volatile __int64 *)var;
    __int64 old;
    do {
