    Py_BUILD_ASSERT(sizeof(long) == sizeof(*var));
    volatile long *volatile_var = (volatile long *)var;
    long old;
    do {
        old = *volatile_var;
    } while(_InterlockedCompareExchange(volatile_var, old, old) != old);
#endif
    return old;
}

