        opt.ticket_key_type = PSA_KEY_TYPE_AES;
        opt.ticket_key_bits = 192;
    } else if (strcmp(buf, "AES-256-CCM")) {
        opt.ticket_alg = PSA_ALG_CCM;
        opt.ticket_key_type = PSA_KEY_TYPE_AES;
        opt.ticket_key_bits = 256;
    } else if (strcmp(buf, "ARIA-128-CCM")) {
