    // Free modules only after all wayland termination functions are called
    if (_glfw.platform.platformID != GLFW_PLATFORM_WAYLAND)
    {
        _glfwPlatformFreeModule(_glfw.egl.handle);
        _glfw.egl.handle = NULL;
